import { Command } from 'commander';
import { docsServer } from '../server/docs-server';

export const docsPreviewCommand = new Command('preview-docs')
  .description('Generate and serve documentation preview')
  .option('-p, --port <number>', 'Port to serve on', '3000')
  .option('-o, --open', 'Open browser automatically', false)
  .action(async (options) => {
    const server = docsServer(options.port);

    // Generate docs if needed
    await server.generateDocs();

    server.listen();

    if (options.open) {
      const { open } = await import('open');
      open(`http://localhost:${options.port}`);
    }

    console.log(`Documentation preview available at http://localhost:${options.port}`);
  });
```

3. Create `src/server/docs-server.ts`:
```typescript
import express from 'express';
import { readFileSync } from 'fs';
import { join } from 'path';

export const docsServer = (port: number) => {
  const app = express();
  const docsDir = join(process.cwd(), 'docs');

  app.get('/', (req, res) => {
    const readme = readFileSync(join(docsDir, 'README.md'), 'utf8');
    res.send(readme);
  });

  app.get('/:path*', (req, res) => {
    const filePath = join(docsDir, req.params.path);
    try {
      const content = readFileSync(filePath, 'utf8');
      res.send(content);
    } catch {
      res.status(404).send('Not found');
    }
  });

  return {
    listen: () => {
      app.listen(port, () => {
        console.log(`Docs server running on port ${port}`);
      });
    }
  };
};
```

